#include <bits/stdc++.h>
using namespace std;

int minCoins(vector<int>& coins, int sum) {
    vector<int> dp(sum + 1, sum + 1);
    dp[0] = 0;

    for(int i = 1; i <= sum; i++) {
        for(int coin : coins) {
            if(coin <= i) {
                dp[i] = min(dp[i], dp[i - coin] + 1);
            }
        }
    }

    return dp[sum] > sum ? -1 : dp[sum];
}

int main() {
    int n, sum;
    cin >> n >> sum;

    vector<int> coins(n);
    for(int i = 0; i < n; i++) {
        cin >> coins[i];
    }

    cout << minCoins(coins, sum) << endl;

    return 0;
}
